=== UNPATCHED CCFFilterAppInstanceEA — vulnerable bounds check (pseudo_c) ===

// After finding EA name match 'ClusteredApplicationInstance':
rdx = *(rbx + 6);                    // rdx = EaValueLength (from offset 6)

if (0x10 == rdx) {                   // GUID-only path (16 bytes) — handled correctly
    *arg4 = *(*(rbx + 5) + rbx + 9); // read 16 bytes
    *arg5 = 0;
    goto label_1c0009a48;
}

if (0x14 >= rdx) {                   // BUG: '0x14 >= rdx' means fall-through when EaValueLength <= 0x14
                                      // Should be '0x14 <= rdx' (only proceed when EaValueLength >= 0x14)
    uint64_t rax_7 = *(rbx + 5);     // rax_7 = EaNameLength
    *arg4 = *(rax_7 + rbx + 9);      // OOB READ: 16 bytes from EaValue
    rdx = *(rax_7 + rbx + 0x19);     // OOB READ: 4 more bytes from EaValue+16
    *arg5 = rdx;
    goto label_1c0009a48;
}

// Error path — only reached when EaValueLength > 0x14 (WRONG: should be < 0x14)
rdi = -0x3fffffad;                   // 0xC0000053 error status

=== PATCHED version (correct comparison) ===
if (0x14 <= rdx) {                   // CORRECT: only proceed when EaValueLength >= 0x14
    // ... safe 20-byte read ...
}
// Error path now correctly reached when EaValueLength < 0x14
